"""Check registry for the rigor gate. Concrete checks land in wave_6/03."""

from __future__ import annotations

from collections.abc import Callable

from noosphere.models import CheckResult, RigorSubmission

_CHECKS: dict[str, Callable[[RigorSubmission], CheckResult]] = {}


def register(name: str, fn: Callable[[RigorSubmission], CheckResult]) -> None:
    _CHECKS[name] = fn


def all_checks() -> dict[str, Callable[[RigorSubmission], CheckResult]]:
    return dict(_CHECKS)

"""Gate: run all registered checks, aggregate, record to ledger and store."""

from __future__ import annotations

import hashlib
from concurrent.futures import ThreadPoolExecutor, as_completed
from typing import TYPE_CHECKING

from noosphere.models import (
    Actor,
    CheckResult,
    ContextMeta,
    RigorSubmission,
    RigorVerdict,
)
from noosphere.rigor_gate.checks import all_checks

if TYPE_CHECKING:
    from noosphere.ledger import Ledger


class GateBlocked(Exception):
    """Raised when a submission fails the rigor gate."""

    def __init__(self, verdict: RigorVerdict) -> None:
        self.verdict = verdict
        super().__init__(f"Gate blocked: {verdict.verdict}")


class Gate:
    def __init__(self, store: object, ledger: "Ledger | None" = None) -> None:
        self.store = store
        self._ledger = ledger

    def submit(self, submission: RigorSubmission) -> RigorVerdict:
        checks = all_checks()
        results = self._run_checks(checks, submission)
        verdict_str, conditions = self._aggregate(results)
        entry_id = self._record_ledger(submission, verdict_str)

        verdict = RigorVerdict(
            verdict=verdict_str,
            checks_run=results,
            conditions=conditions,
            reviewed_by=[submission.author],
            ledger_entry_id=entry_id,
        )

        self.store.insert_rigor_submission(submission)  # type: ignore[union-attr]
        self.store.insert_rigor_verdict(verdict)  # type: ignore[union-attr]
        return verdict

    # ------------------------------------------------------------------

    @staticmethod
    def _run_checks(
        checks: dict[str, object],
        submission: RigorSubmission,
    ) -> list[CheckResult]:
        if not checks:
            return []
        results: list[CheckResult] = []
        with ThreadPoolExecutor() as pool:
            futures = {
                pool.submit(fn, submission): name  # type: ignore[arg-type]
                for name, fn in checks.items()
            }
            for fut in as_completed(futures):
                results.append(fut.result())
        return results

    @staticmethod
    def _aggregate(
        results: list[CheckResult],
    ) -> tuple[str, list[str]]:
        conditions: list[str] = []
        has_blocker = False
        for r in results:
            if not r.pass_:
                has_blocker = True
            elif r.detail.startswith("CONDITION:"):
                conditions.append(r.detail[len("CONDITION:") :].strip())
        if has_blocker:
            return "fail", []
        if conditions:
            return "pass_with_conditions", conditions
        return "pass", []

    def _record_ledger(self, submission: RigorSubmission, verdict_str: str) -> str:
        if self._ledger is None:
            return f"rigor-{submission.submission_id}"

        return self._ledger.append(
            actor=submission.author,
            method_id=None,
            inputs_hash=hashlib.sha256(
                submission.model_dump_json().encode()
            ).hexdigest(),
            outputs_hash=hashlib.sha256(verdict_str.encode()).hexdigest(),
            inputs_ref=f"rigor_submission:{submission.submission_id}",
            outputs_ref=f"rigor_verdict:{verdict_str}",
            context=ContextMeta(
                tenant_id="rigor_gate",
                correlation_id=submission.submission_id,
            ),
        )

"""Freshness derivation — always computed, never cached."""

from __future__ import annotations

from datetime import datetime, timezone
from typing import Any, Optional

from noosphere.models import DecayPolicy, Freshness

from noosphere.decay.policies import PolicyEvaluator, evaluator_for, _resolve_object


def utc_now() -> datetime:
    return datetime.now(timezone.utc)


def compute_freshness(
    store: Any,
    object_id: str,
    as_of: Optional[datetime] = None,
) -> Freshness:
    """Derive freshness from last_validated_at and bound policies.

    NEVER caches — always recomputes from current state.
    """
    if as_of is None:
        as_of = utc_now()

    obj = _resolve_object(store, object_id)
    if obj is None:
        return Freshness.STALE

    current = getattr(obj, "freshness", None)
    if current == Freshness.RETIRED:
        return Freshness.RETIRED

    policies = _get_bound_policies(store, object_id)
    if not policies:
        return Freshness.FRESH

    evaluators = [evaluator_for(p) for p in policies]
    any_triggered = any(
        ev.should_trigger(store, object_id, as_of) for ev in evaluators
    )

    if any_triggered:
        return Freshness.STALE

    last_validated = getattr(obj, "last_validated_at", None)
    if last_validated is None:
        return Freshness.AGING

    return Freshness.FRESH


def _get_bound_policies(store: Any, object_id: str) -> list[DecayPolicy]:
    """Retrieve all DecayPolicy models bound to an object."""
    try:
        from sqlmodel import select
        from noosphere.store import StoredObjectPolicyBinding, StoredDecayPolicy

        with store.session() as s:
            bindings = s.exec(
                select(StoredObjectPolicyBinding).where(
                    StoredObjectPolicyBinding.object_id == object_id
                )
            ).all()
            policies = []
            for b in bindings:
                row = s.get(StoredDecayPolicy, b.policy_id)
                if row is not None:
                    policies.append(DecayPolicy.model_validate_json(row.payload_json))
            return policies
    except Exception:
        return []

from __future__ import annotations

import logging
from concurrent.futures import ThreadPoolExecutor, as_completed
from typing import Any

from noosphere.models import Conclusion, ReviewReport, SwarmReport
from noosphere.peer_review.reviewer import Reviewer
from noosphere.peer_review.reviewers import all_reviewers
from noosphere.store import Store

logger = logging.getLogger(__name__)


class SwarmOrchestrator:
    def __init__(self, store: Store) -> None:
        self._store = store

    def run(
        self,
        conclusion_id: str,
        *,
        context: dict[str, Any] | None = None,
    ) -> SwarmReport:
        conclusion = self._store.get_conclusion(conclusion_id)
        if conclusion is None:
            raise ValueError(f"Conclusion {conclusion_id} not found")

        reviewers: list[Reviewer] = [cls() for cls in all_reviewers()]
        ctx = context or {}
        reports = self._run_reviews(reviewers, conclusion, ctx)

        for report in reports:
            self._store.insert_review_report(report)

        return SwarmReport(
            conclusion_id=conclusion_id,
            reviews=reports,
            rebuttals=[],
        )

    def _run_reviews(
        self,
        reviewers: list[Reviewer],
        conclusion: Conclusion,
        context: dict[str, Any],
    ) -> list[ReviewReport]:
        reports: list[ReviewReport] = []
        with ThreadPoolExecutor() as executor:
            futures = {
                executor.submit(r.review, conclusion, context): r
                for r in reviewers
            }
            for future in as_completed(futures):
                reviewer = futures[future]
                try:
                    reports.append(future.result())
                except Exception:
                    logger.exception("Reviewer %s failed", reviewer.name)
        return reports

