            return CheckResult(
                check_name=CHECK_NAME,
                pass_=False,
                detail=f"provenance_lookup_failed: {claim_id}",
            )
        if not edges:
            return CheckResult(
                check_name=CHECK_NAME,
                pass_=False,
                detail=f"claim_lacks_provenance: {claim_id}",
